package org.example;
import java.util.Scanner;
import java.nio.charset.StandardCharsets;
import org.example.Command.Result;

import dagger.Component;

@Component
interface CommandRouterFactory {
    CommandRouter router();
}

public class App {

    public Result callCommandRouter(CommandRouter cmdRouter, String cmd) {
        return cmdRouter.route(cmd);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in, StandardCharsets.UTF_8);
        CommandRouterFactory cmdRouterFactory = DaggerCommandRouterFactory.create();
        CommandRouter commandRouter = cmdRouterFactory.router();
        App AtmApp = new App();

        while(scanner.hasNextLine()) {
            Result unused = AtmApp.callCommandRouter(commandRouter, scanner.nextLine());
        }

        scanner.close();

    }
}
